headStyles:
body { background: var(--dark-bg); }

/* ── Stats bar (mirrors scorecard.html) ── */
.stats-bar {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  margin-top: -40px;
  position: relative;
  z-index: 2;
}
.stat-card {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 24px 20px;
  text-align: center;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}
.stat-card .stat-number {
  font-family: 'Montserrat', sans-serif;
  font-size: 36px;
  font-weight: 800;
  color: var(--text-white);
  line-height: 1;
  margin-bottom: 6px;
}
.stat-card .stat-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.5);
}
@media (max-width: 720px) {
  .stats-bar { grid-template-columns: repeat(2, 1fr); gap: 10px; }
  .stat-card .stat-number { font-size: 28px; }
}
@media (max-width: 480px) {
  .stats-bar { grid-template-columns: 1fr 1fr; gap: 8px; margin-top: -30px; }
  .stat-card { padding: 16px 12px; }
  .stat-card .stat-number { font-size: 24px; }
}

/* ── Updated badge (mirrors scorecard.html) ── */
.updated-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 20px;
  padding: 6px 14px;
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.5);
  letter-spacing: 0.5px;
  margin-top: 20px;
}
.updated-badge .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-success);
  display: inline-block;
}

/* ── Jump-nav strip ── */
.jump-nav {
  margin-top: 32px;
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 14px 18px;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}
.jump-nav-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: rgba(255, 255, 255, 0.5);
  margin-right: 12px;
  display: inline-block;
}
.jump-nav-links {
  display: inline-flex;
  flex-wrap: wrap;
  gap: 6px;
  align-items: center;
}
.jump-nav-links a {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  text-decoration: none;
  padding: 6px 12px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(255, 255, 255, 0.04);
  transition: color 0.15s, background 0.15s, border-color 0.15s;
}
.jump-nav-links a:hover {
  color: var(--text-white);
  background: rgba(255, 255, 255, 0.08);
  border-color: rgba(255, 255, 255, 0.18);
}

/* ── Methodology card sections ── */
.meth-cards {
  display: grid;
  grid-template-columns: 1fr;
  gap: 20px;
  margin-top: 24px;
}
.meth-card {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 14px;
  padding: 28px 32px;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  scroll-margin-top: 100px;
}
@media (max-width: 600px) {
  .meth-card { padding: 22px 18px; }
}
.meth-card .mc-eyebrow {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: var(--text-accent);
  margin: 0 0 8px;
}
.meth-card h2 {
  font-family: 'Montserrat', sans-serif;
  font-size: 26px;
  font-weight: 800;
  color: var(--text-white);
  margin: 0 0 16px;
  line-height: 1.2;
}
.meth-card h3 {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 700;
  color: var(--text-accent);
  text-transform: uppercase;
  letter-spacing: 1.2px;
  margin: 22px 0 10px;
}
.meth-card p, .meth-card li {
  font-family: 'Roboto Slab', serif;
  font-size: 15px;
  line-height: 1.75;
  color: rgba(255, 255, 255, 0.8);
}
.meth-card p { margin: 0 0 14px; }
.meth-card ul, .meth-card ol { padding-left: 22px; margin: 6px 0 16px; }
.meth-card li { margin-bottom: 6px; }
.meth-card a { color: var(--text-accent); }
.meth-card strong { color: var(--text-white); font-weight: 700; }

/* ── Inline supporting blocks ── */
.formula-box {
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  padding: 16px 20px;
  border-radius: 10px;
  font-family: 'JetBrains Mono', 'Menlo', monospace;
  font-size: 15px;
  color: var(--text-white);
  margin: 12px 0 18px;
  overflow-x: auto;
}

.pillar-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 14px;
  margin: 18px 0 22px;
}
.pillar-card {
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-left: 3px solid var(--text-accent);
  padding: 16px 18px;
  border-radius: 8px;
}
.pillar-card .pc-name {
  font-family: 'Montserrat', sans-serif;
  font-size: 22px;
  font-weight: 800;
  color: var(--text-accent);
  line-height: 1;
}
.pillar-card .pc-range {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: rgba(255, 255, 255, 0.55);
  margin-top: 6px;
}
.pillar-card .pc-desc {
  font-family: 'Roboto Slab', serif;
  font-size: 14px;
  color: rgba(255, 255, 255, 0.78);
  margin-top: 10px;
  line-height: 1.6;
}

.weight-table {
  width: 100%;
  border-collapse: collapse;
  margin: 12px 0 8px;
}
.weight-table th, .weight-table td {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  text-align: left;
  padding: 10px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}
.weight-table th {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: rgba(255, 255, 255, 0.5);
}
.weight-table td {
  color: rgba(255, 255, 255, 0.78);
  font-weight: 500;
}
.weight-table td.mult {
  font-family: 'JetBrains Mono', 'Menlo', monospace;
  font-weight: 700;
  color: var(--text-accent);
}

.grade-scale {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: 10px;
  margin: 14px 0 10px;
}
.grade-tile {
  padding: 14px 12px;
  border-radius: 10px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(19, 45, 68, 0.4);
  text-align: center;
}
.grade-tile .gt-letter {
  font-family: 'Montserrat', sans-serif;
  font-size: 28px;
  font-weight: 900;
  line-height: 1;
}
.grade-tile .gt-range {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: rgba(255, 255, 255, 0.55);
  margin-top: 6px;
}
.grade-tile .gt-label {
  font-family: 'Roboto Slab', serif;
  font-size: 12px;
  color: rgba(255, 255, 255, 0.7);
  margin-top: 4px;
}

.callout {
  background: rgba(255, 255, 255, 0.04);
  border-left: 3px solid var(--text-accent);
  padding: 16px 20px;
  border-radius: 0 10px 10px 0;
  margin: 18px 0 6px;
}
.callout p:last-child { margin-bottom: 0; }

.back-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  text-decoration: none;
  padding: 8px 14px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  border-radius: 20px;
  margin-top: 24px;
  transition: background 0.15s, border-color 0.15s;
}
.back-link:hover {
  background: rgba(255, 255, 255, 0.06);
  border-color: rgba(255, 255, 255, 0.28);
}

.last-reviewed {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  color: rgba(255, 255, 255, 0.5);
  margin-top: 18px;
  padding-top: 14px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
}
